const quizQuestions=[{id:1,question:"What’s your primary work style?",options:[{text:"Mostly seated, focused tasks (coding, writing)",value:"seated",icon:"fa-laptop"},{text:"Mix of sitting and standing (meetings, creative work)",value:"mixed",icon:"fa-people-arrows"},{text:"Active and moving (design, teaching, frequent breaks)",value:"active",icon:"fa-person-walking"}]},{id:2,question:"What’s your budget for a chair?",options:[{text:"Under $200",value:"budget",icon:"fa-wallet"},{text:"$200 – $600",value:"midrange",icon:"fa-credit-card"},{text:"$600+ (premium ergonomics)",value:"premium",icon:"fa-gem"}]},{id:3,question:"How much desk space do you have?",options:[{text:"Small (under 48″ wide)",value:"small",icon:"fa-ruler-combined"},{text:"Medium (48″ – 72″)",value:"medium",icon:"fa-ruler"},{text:"Large (over 72″ or L‑shaped)",value:"large",icon:"fa-maximize"}]},{id:4,question:"What’s your biggest pain point?",options:[{text:"Neck/shoulder strain",value:"neck",icon:"fa-user-injured"},{text:"Lower back discomfort",value:"back",icon:"fa-bed"},{text:"Eye fatigue / headaches",value:"eyes",icon:"fa-eye"},{text:"Wrist/hand fatigue",value:"wrist",icon:"fa-hand"}]},{id:5,question:"How important is aesthetics?",options:[{text:"Function over form—just make it work",value:"functional",icon:"fa-screwdriver-wrench"},{text:"Balanced—good looks but practical",value:"balanced",icon:"fa-scale-balanced"},{text:"Design‑first—my workspace is my sanctuary",value:"design",icon:"fa-palette"}]}],productRecommendations={"seated-budget-small-neck-functional":[{name:"Staples Hyken Mesh Chair",category:"Chair",price:"$139.99",link:"/deals/#hyken"},{name:"Simple Monitor Arm",category:"Accessory",price:"$79.99",link:"/deals/#arm"}],"mixed-midrange-medium-back-balanced":[{name:"2026 Electric Standing Desk",category:"Desk",price:"$449.99",link:"/deals/#desk"},{name:"Ergonomic Mesh Chair Pro",category:"Chair",price:"$699.99",link:"/deals/#chair"}],default:[{name:"2026 Electric Standing Desk",category:"Desk",price:"$449.99",link:"/deals/#desk"},{name:"Ergonomic Mesh Chair Pro",category:"Chair",price:"$699.99",link:"/deals/#chair"},{name:"32″ 4K IPS Monitor",category:"Monitor",price:"$529.99",link:"/deals/#monitor"}]};let currentQuestion=0,answers={};function startQuiz(){currentQuestion=0,answers={},document.getElementById("quiz-container").innerHTML=renderQuestion(currentQuestion)}function renderQuestion(e){const t=quizQuestions[e];return`\n        <div class="quiz-question animate-slide-up">\n            <div class="flex justify-between items-center mb-8">\n                <h3 class="text-2xl font-bold text-neutral-900 dark:text-white">Question ${e+1} of ${quizQuestions.length}</h3>\n                <span class="text-sm text-neutral-600 dark:text-neutral-400">${Math.round(e/quizQuestions.length*100)}% complete</span>\n            </div>\n            <h2 class="text-3xl md:text-4xl font-black tracking-tight text-neutral-900 dark:text-white mb-10">${t.question}</h2>\n            <div class="grid md:grid-cols-3 gap-6">\n                ${t.options.map((t,n)=>`\n                    <button onclick="selectOption(${e}, '${t.value}')" \n                            class="quiz-option p-8 rounded-2xl border-2 border-neutral-300 dark:border-neutral-700 bg-white dark:bg-neutral-800 hover:border-accent hover:shadow-xl transition-all text-left group">\n                        <div class="flex items-center justify-between mb-6">\n                            <i class="fa-solid ${t.icon} text-3xl text-accent"></i>\n                            <span class="text-xs font-bold uppercase tracking-wider text-neutral-500">Option ${n+1}</span>\n                        </div>\n                        <p class="text-lg font-semibold text-neutral-900 dark:text-white group-hover:text-accent transition-colors">${t.text}</p>\n                    </button>\n                `).join("")}\n            </div>\n            <div class="mt-12 flex justify-between">\n                <button onclick="prevQuestion()" ${0===e?"disabled":""} \n                        class="px-8 py-3 rounded-xl border border-neutral-300 dark:border-neutral-700 text-neutral-700 dark:text-neutral-300 disabled:opacity-50 disabled:cursor-not-allowed">\n                    <i class="fa-solid fa-arrow-left mr-2"></i> Back\n                </button>\n                <div class="text-sm text-neutral-600 dark:text-neutral-400">\n                    Select one to continue\n                </div>\n            </div>\n        </div>\n    `}function selectOption(e,t){answers[quizQuestions[e].id]=t,currentQuestion<quizQuestions.length-1?(currentQuestion++,document.getElementById("quiz-container").innerHTML=renderQuestion(currentQuestion)):showResults()}function prevQuestion(){currentQuestion>0&&(currentQuestion--,document.getElementById("quiz-container").innerHTML=renderQuestion(currentQuestion))}function showResults(){const e=Object.values(answers).join("-"),t=productRecommendations[e]||productRecommendations.default;document.getElementById("quiz-container").innerHTML=`\n        <div class="quiz-results animate-fade-in">\n            <div class="text-center mb-12">\n                <i class="fa-solid fa-trophy text-6xl text-accent mb-6"></i>\n                <h2 class="text-4xl font-black tracking-tight text-neutral-900 dark:text-white">Your Perfect Workspace</h2>\n                <p class="text-neutral-600 dark:text-neutral-400 mt-4 max-w-2xl mx-auto">\n                    Based on your answers, here are our top recommendations for a healthier, more productive setup.\n                </p>\n            </div>\n            <div class="grid md:grid-cols-2 gap-8 mb-12">\n                ${t.map(e=>`\n                    <div class="bg-white dark:bg-neutral-800 p-8 rounded-2xl border border-neutral-200 dark:border-neutral-700">\n                        <div class="flex items-center gap-4 mb-6">\n                            <div class="w-14 h-14 bg-gradient-to-br from-primary to-accent rounded-xl flex items-center justify-center text-white text-2xl">\n                                <i class="fa-solid fa-${"Chair"===e.category?"chair":"Desk"===e.category?"table":"star"}"></i>\n                            </div>\n                            <div>\n                                <p class="text-xs font-bold uppercase tracking-wider text-accent">${e.category}</p>\n                                <h3 class="font-bold text-xl text-neutral-900 dark:text-white">${e.name}</h3>\n                            </div>\n                        </div>\n                        <p class="text-accent font-bold text-2xl">${e.price}</p>\n                        <a href="${e.link}" class="block w-full mt-6 text-center bg-neutral-900 dark:bg-white text-white dark:text-neutral-900 py-3 rounded-xl font-semibold hover:bg-accent hover:text-white transition-colors">\n                            View Details & Price\n                        </a>\n                    </div>\n                `).join("")}\n            </div>\n            <div class="text-center">\n                <button onclick="startQuiz()" class="bg-white dark:bg-neutral-800 text-neutral-900 dark:text-white border border-neutral-300 dark:border-neutral-700 px-10 py-4 rounded-2xl font-bold hover:shadow-xl transition-all mr-4">\n                    <i class="fa-solid fa-rotate-left mr-2"></i> Retake Quiz\n                </button>\n                <a href="/deals/" class="bg-gradient-to-r from-primary to-accent text-white px-10 py-4 rounded-2xl font-bold hover:shadow-xl transition-all inline-block">\n                    Browse All Products <i class="fa-solid fa-arrow-right ml-2"></i>\n                </a>\n            </div>\n        </div>\n    `}document.addEventListener("DOMContentLoaded",function(){document.getElementById("quiz-container")});